import { useState, useEffect, useMemo } from 'react';
import { api } from '../api';
import { User } from '../types';

interface Stats {
  userCount: number;
  taskCount: number;
  statusCounts: { status: string; count: number }[];
  priorityCounts: { priority: string; count: number }[];
  labelCount: number;
  commentCount: number;
  overdueCount: number;
}

type SortKey = 'id' | 'username' | 'email' | 'role' | 'created_at';
type SortDir = 'asc' | 'desc';

const PAGE_SIZE = 5;

function priorityLabel(p: string) {
  switch (p) {
    case 'urgent': return 'Acil';
    case 'high': return 'Yüksek';
    case 'medium': return 'Orta';
    case 'low': return 'Düşük';
    default: return p;
  }
}

function exportCSV(users: User[]) {
  const header = 'ID,Kullanıcı Adı,E-posta,Rol,Kayıt Tarihi\n';
  const rows = users.map(u => {
    const date = new Date((u as any).created_at).toLocaleDateString('tr-TR');
    return `${u.id},"${u.username}","${u.email}",${u.role},"${date}"`;
  }).join('\n');
  const blob = new Blob(['\uFEFF' + header + rows], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `kullanıcılar_${new Date().toISOString().slice(0, 10)}.csv`;
  a.click();
  URL.revokeObjectURL(url);
}

import { 
  ShieldCheck, Users, FileText, CheckCircle2, AlertCircle, 
  Tag, MessageSquare, BarChart3, ArrowUp, 
  ArrowDown, Minus, Search, X, Download, ChevronLeft, 
  ChevronRight, Filter
} from 'lucide-react';

export default function AdminPage() {
  const [users, setUsers] = useState<User[]>([]);
  const [stats, setStats] = useState<Stats | null>(null);
  const [loading, setLoading] = useState(true);

  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState<'all' | 'admin' | 'user'>('all');
  const [sortKey, setSortKey] = useState<SortKey>('id');
  const [sortDir, setSortDir] = useState<SortDir>('asc');
  const [page, setPage] = useState(1);

  useEffect(() => {
    Promise.all([api.admin.users(), api.admin.stats()])
      .then(([u, s]) => { setUsers(u); setStats(s); })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const getCount = (status: string) =>
    stats?.statusCounts.find(s => s.status === status)?.count || 0;
  const getPriorityCount = (priority: string) =>
    stats?.priorityCounts?.find(p => p.priority === priority)?.count || 0;

  const todoCount = getCount('todo');
  const inProgressCount = getCount('in-progress');
  const doneCount = getCount('done');
  const totalTasks = stats?.taskCount || 0;

  const handleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortKey(key);
      setSortDir('asc');
    }
    setPage(1);
  };

  const sortArrow = (key: SortKey) => {
    if (sortKey !== key) return <Minus size={14} className="text-muted opacity-30" />;
    return sortDir === 'asc' 
      ? <ArrowUp size={14} className="text-primary" /> 
      : <ArrowDown size={14} className="text-primary" />;
  };

  const processedUsers = useMemo(() => {
    let result = [...users];

    if (roleFilter !== 'all') {
      result = result.filter(u => u.role === roleFilter);
    }

    if (search.trim()) {
      const q = search.toLowerCase();
      result = result.filter(u =>
        u.username.toLowerCase().includes(q) ||
        u.email.toLowerCase().includes(q)
      );
    }

    result.sort((a, b) => {
      let aVal: string | number = '';
      let bVal: string | number = '';

      if (sortKey === 'id') { aVal = a.id; bVal = b.id; }
      else if (sortKey === 'username') { aVal = a.username.toLowerCase(); bVal = b.username.toLowerCase(); }
      else if (sortKey === 'email') { aVal = a.email.toLowerCase(); bVal = b.email.toLowerCase(); }
      else if (sortKey === 'role') { aVal = a.role; bVal = b.role; }
      else if (sortKey === 'created_at') { aVal = (a as any).created_at; bVal = (b as any).created_at; }

      if (aVal < bVal) return sortDir === 'asc' ? -1 : 1;
      if (aVal > bVal) return sortDir === 'asc' ? 1 : -1;
      return 0;
    });

    return result;
  }, [users, search, roleFilter, sortKey, sortDir]);

  const totalPages = Math.max(1, Math.ceil(processedUsers.length / PAGE_SIZE));
  const pagedUsers = processedUsers.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);

  useEffect(() => { setPage(1); }, [search, roleFilter]);

  if (loading) return (
    <div className="admin-skeleton-container" style={{marginTop: '2rem'}}>
      <div className="skeleton-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1rem', marginBottom: '2rem' }}>
        {[1, 2, 3, 4].map(i => <div key={i} className="skeleton-box skeleton-card" style={{height:'100px', borderRadius: '12px'}} />)}
      </div>
      <div className="skeleton-box skeleton-card" style={{height:'400px', borderRadius: '12px'}} />
    </div>
  );

  return (
    <div className="admin-container">
      <div className="page-header">
        <h2 style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <ShieldCheck size={28} className="text-primary" />
          Sistem Yönetimi
        </h2>
        <div className="header-actions">
          <button className="btn-outline-pill" onClick={() => exportCSV(processedUsers)}>
            <Download size={16} />
            <span>Verileri Dışa Aktar</span>
          </button>
        </div>
      </div>

      {/* Stat Cards */}
      <div className="admin-stats-grid">
        <div className="admin-stat-card-modern">
          <div className="admin-stat-icon-box bg-purple-soft">
            <Users size={24} className="text-purple" />
          </div>
          <div className="admin-stat-info">
            <span className="admin-stat-number">{stats?.userCount || 0}</span>
            <span className="admin-stat-label">Toplam Kullanıcı</span>
          </div>
        </div>
        <div className="admin-stat-card-modern">
          <div className="admin-stat-icon-box bg-blue-soft">
            <FileText size={24} className="text-blue" />
          </div>
          <div className="admin-stat-info">
            <span className="admin-stat-number">{stats?.taskCount || 0}</span>
            <span className="admin-stat-label">Toplam Görev</span>
          </div>
        </div>
        <div className="admin-stat-card-modern">
          <div className="admin-stat-icon-box bg-green-soft">
            <CheckCircle2 size={24} className="text-green" />
          </div>
          <div className="admin-stat-info">
            <span className="admin-stat-number">{doneCount}</span>
            <span className="admin-stat-label">Tamamlanan</span>
          </div>
        </div>
        <div className="admin-stat-card-modern">
          <div className="admin-stat-icon-box bg-red-soft">
            <AlertCircle size={24} className="text-red" />
          </div>
          <div className="admin-stat-info">
            <span className="admin-stat-number text-red">{stats?.overdueCount || 0}</span>
            <span className="admin-stat-label">Geciken</span>
          </div>
        </div>
      </div>

      {/* Detail Stats Row */}
      <div className="admin-meta-info-bar">
        <div className="meta-item">
          <Tag size={14} />
          <span>Etiket: <strong>{stats?.labelCount || 0}</strong></span>
        </div>
        <div className="meta-item">
          <MessageSquare size={14} />
          <span>Yorum: <strong>{stats?.commentCount || 0}</strong></span>
        </div>
        <div className="divider-v"></div>
        <div className="meta-priority-group">
          {['urgent', 'high', 'medium', 'low'].map(p => (
            <div key={p} className="meta-priority-item">
              <span className={`dot-prio prio-${p}`}></span>
              <span>{priorityLabel(p)}: <strong>{getPriorityCount(p)}</strong></span>
            </div>
          ))}
        </div>
      </div>

      {/* Visual Charts & Table Area */}
      <div className="admin-content-layout">
        {/* Status Distribution */}
        {totalTasks > 0 && (
          <div className="admin-chart-section">
            <h3 className="section-title-sm">
              <BarChart3 size={16} />
              Görev Durum Analizi
            </h3>
            <div className="modern-status-bar">
              {todoCount > 0 && (
                <div className="status-segment todo" style={{ width: `${(todoCount / totalTasks) * 100}%` }}>
                  <span className="segment-label">{Math.round((todoCount / totalTasks) * 100)}%</span>
                </div>
              )}
              {inProgressCount > 0 && (
                <div className="status-segment progress" style={{ width: `${(inProgressCount / totalTasks) * 100}%` }}>
                  <span className="segment-label">{Math.round((inProgressCount / totalTasks) * 100)}%</span>
                </div>
              )}
              {doneCount > 0 && (
                <div className="status-segment done" style={{ width: `${(doneCount / totalTasks) * 100}%` }}>
                  <span className="segment-label">{Math.round((doneCount / totalTasks) * 100)}%</span>
                </div>
              )}
            </div>
            <div className="status-legend-modern">
              <div className="legend-pill">
                <span className="pill-dot bg-orange"></span>
                <span>Yapılacak ({todoCount})</span>
              </div>
              <div className="legend-pill">
                <span className="pill-dot bg-blue"></span>
                <span>Devam Ediyor ({inProgressCount})</span>
              </div>
              <div className="legend-pill">
                <span className="pill-dot bg-green"></span>
                <span>Tamamlandı ({doneCount})</span>
              </div>
            </div>
          </div>
        )}

        {/* User Management Section */}
        <div className="admin-table-section">
          <div className="table-header-modern">
            <div className="header-left">
              <h3 className="section-title-sm">Kullanıcı Yönetimi</h3>
              <span className="result-count">{processedUsers.length} kişi bulundu</span>
            </div>
            <div className="header-right">
              <div className="search-box-modern">
                <Search size={18} className="search-icon" />
                <input
                  type="text"
                  placeholder="İsim veya e-posta ara..."
                  value={search}
                  onChange={e => setSearch(e.target.value)}
                />
                {search && <button className="clear-search" onClick={() => setSearch('')}><X size={14} /></button>}
              </div>
              <div className="filter-box-modern">
                <Filter size={18} className="filter-icon" />
                <select
                  value={roleFilter}
                  onChange={e => setRoleFilter(e.target.value as any)}
                >
                  <option value="all">Tüm Roller</option>
                  <option value="admin">Admin</option>
                  <option value="user">Kullanıcı</option>
                </select>
              </div>
            </div>
          </div>

          <div className="table-container-modern">
            <table className="admin-data-table">
              <thead>
                <tr>
                  <th onClick={() => handleSort('id')}>ID {sortArrow('id')}</th>
                  <th onClick={() => handleSort('username')}>Kullanıcı {sortArrow('username')}</th>
                  <th onClick={() => handleSort('email')}>E-posta {sortArrow('email')}</th>
                  <th onClick={() => handleSort('role')}>Rol {sortArrow('role')}</th>
                  <th onClick={() => handleSort('created_at')}>Tarih {sortArrow('created_at')}</th>
                </tr>
              </thead>
              <tbody>
                {pagedUsers.length === 0 ? (
                  <tr>
                    <td colSpan={5}>
                      <div className="empty-state-table">
                        <Search size={48} className="text-muted opacity-20" />
                        <h4>Arama kriterine uygun sonuç bulunamadı</h4>
                        <p>Lütfen farklı bir kelime deneyin veya filtreleri sıfırlayın.</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  pagedUsers.map(u => (
                    <tr key={u.id}>
                      <td className="text-muted font-mono">{u.id}</td>
                      <td>
                        <div className="user-info-cell">
                          <div className="user-avatar-mini">
                            {u.username.substring(0, 1).toUpperCase()}
                          </div>
                          <span className="username-bold">{u.username}</span>
                        </div>
                      </td>
                      <td>{u.email}</td>
                      <td>
                        <span className={`role-badge ${u.role}`}>
                          {u.role === 'admin' ? <ShieldCheck size={12} /> : <Users size={12} />}
                          {u.role}
                        </span>
                      </td>
                      <td className="text-muted text-sm">
                        {new Date((u as any).created_at).toLocaleDateString('tr-TR')}
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>

          {/* New Pagination */}
          {totalPages > 1 && (
            <div className="pagination-modern">
              <button className="page-nav-btn" disabled={page === 1} onClick={() => setPage(p => p - 1)}>
                <ChevronLeft size={18} />
                <span>Önceki</span>
              </button>
              <div className="page-numbers">
                {Array.from({ length: totalPages }, (_, i) => i + 1).map(p => (
                  <button 
                    key={p} 
                    className={`page-num-btn ${p === page ? 'active' : ''}`} 
                    onClick={() => setPage(p)}
                  >
                    {p}
                  </button>
                ))}
              </div>
              <button className="page-nav-btn" disabled={page === totalPages} onClick={() => setPage(p => p + 1)}>
                <span>Sonraki</span>
                <ChevronRight size={18} />
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback, useRef, FormEvent, DragEvent } from 'react';
import { api } from '../api';
import { Task, Label, Comment, ActivityLog } from '../types';

/* ---- Helpers ---- */
function priorityLabel(p: string) {
  switch (p) {
    case 'urgent': return 'Acil';
    case 'high': return 'Yüksek';
    case 'medium': return 'Orta';
    case 'low': return 'Düşük';
    default: return p;
  }
}

function statusLabel(s: string) {
  switch (s) {
    case 'todo': return 'Yapılacak';
    case 'in-progress': return 'Devam ediyor';
    case 'done': return 'Tamamlandı';
    default: return s;
  }
}

function isOverdue(dueDate: string | null, status: string): boolean {
  if (!dueDate || status === 'done') return false;
  return new Date(dueDate) < new Date(new Date().toISOString().split('T')[0]);
}

function timeAgo(dateStr: string): string {
  const now = new Date();
  const date = new Date(dateStr);
  const diffMs = now.getTime() - date.getTime();
  const diffMins = Math.floor(diffMs / 60000);
  const diffHours = Math.floor(diffMins / 60);
  const diffDays = Math.floor(diffHours / 24);
  if (diffMins < 1) return 'Az önce';
  if (diffMins < 60) return `${diffMins} dk önce`;
  if (diffHours < 24) return `${diffHours} saat önce`;
  if (diffDays === 1) return 'Dün';
  if (diffDays < 7) return `${diffDays} gün önce`;
  return new Date(dateStr).toLocaleDateString('tr-TR');
}

function formatDate(d: string) {
  return new Date(d).toLocaleDateString('tr-TR');
}

/* ---- StatusBadge ---- */
function StatusBadge({ status }: { status: string }) {
  const cls = status === 'todo' ? 'badge-todo' : status === 'in-progress' ? 'badge-in-progress' : 'badge-done';
  return <span className={`badge ${cls}`}>{statusLabel(status)}</span>;
}

function PriorityBadge({ priority }: { priority: string }) {
  return <span className={`badge badge-priority-${priority}`}>{priorityLabel(priority)}</span>;
}

/* ---- Task Form ---- */
interface TaskFormProps {
  initial?: Partial<Task>;
  allLabels: Label[];
  taskLabels?: Label[];
  users: { id: number; username: string }[];
  onSave: (data: any) => Promise<void>;
  onCancel: () => void;
}

function TaskForm({ initial, allLabels, taskLabels, users, onSave, onCancel }: TaskFormProps) {
  const [title, setTitle] = useState(initial?.title || '');
  const [description, setDescription] = useState(initial?.description || '');
  const [status, setStatus] = useState(initial?.status || 'todo');
  const [priority, setPriority] = useState(initial?.priority || 'medium');
  const [dueDate, setDueDate] = useState(initial?.due_date || '');
  const [assigneeIds, setAssigneeIds] = useState<number[]>(
    initial?.assigned_users?.map(u => u.id) || []
  );
  const [selectedLabels, setSelectedLabels] = useState<number[]>(taskLabels?.map(l => l.id) || []);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await onSave({
        title, description, status, priority,
        due_date: dueDate || undefined,
        assignee_ids: assigneeIds,
        labelIds: selectedLabels,
      });
    } catch (err: unknown) {
      const e = err as { body?: { errors?: { message: string }[] } };
      const errs = e.body?.errors;
      setError(errs ? errs.map((x) => x.message).join(', ') : 'Bir hata olustu');
    } finally {
      setLoading(false);
    }
  };

  const toggleLabel = (id: number) => {
    setSelectedLabels(prev => prev.includes(id) ? prev.filter(l => l !== id) : [...prev, id]);
  };

  return (
    <form onSubmit={handleSubmit}>
      <div className="form-group">
        <label>Başlık *</label>
        <input value={title} onChange={e => setTitle(e.target.value)} placeholder="Görev başlığı" required />
      </div>
      <div className="form-group">
        <label>Açıklama</label>
        <textarea value={description} onChange={e => setDescription(e.target.value)} placeholder="İsteğe bağlı açıklama" />
      </div>
      <div className="form-row">
        <div className="form-group">
          <label>Durum</label>
          <select value={status} onChange={e => setStatus(e.target.value as any)}>
            <option value="todo">Yapılacak</option>
            <option value="in-progress">Devam ediyor</option>
            <option value="done">Tamamlandı</option>
          </select>
        </div>
        <div className="form-group">
          <label>Öncelik</label>
          <select value={priority} onChange={e => setPriority(e.target.value as any)}>
            <option value="low">Düşük</option>
            <option value="medium">Orta</option>
            <option value="high">Yüksek</option>
            <option value="urgent">Acil</option>
          </select>
        </div>
      </div>
      <div className="form-row">
        <div className="form-group">
          <label>Bitiş Tarihi</label>
          <input type="date" value={dueDate} onChange={e => setDueDate(e.target.value)} />
        </div>
        <div className="form-group">
          <label>Atanan Kişiler (İsteğe Bağlı)</label>
          <div style={{ maxHeight: '120px', overflowY: 'auto', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)', padding: '0.4rem', display: 'flex', flexDirection: 'column', gap: '0.3rem', background: 'var(--bg-card)' }}>
            {users.map(u => (
              <label key={u.id} style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', cursor: 'pointer', margin: 0, fontWeight: 'normal', fontSize: '0.9rem' }}>
                <input 
                  type="checkbox" 
                  checked={assigneeIds.includes(u.id)}
                  onChange={(e) => {
                    if (e.target.checked) setAssigneeIds([...assigneeIds, u.id]);
                    else setAssigneeIds(assigneeIds.filter(id => id !== u.id));
                  }}
                />
                {u.username}
              </label>
            ))}
          </div>
        </div>
      </div>
      {allLabels.length > 0 && (
        <div className="form-group">
          <label>Etiketler</label>
          <div className="label-picker">
            {allLabels.map(l => (
              <button
                key={l.id}
                type="button"
                className={`label-chip ${selectedLabels.includes(l.id) ? 'label-chip-selected' : ''}`}
                style={{ '--label-color': l.color } as any}
                onClick={() => toggleLabel(l.id)}
              >
                {l.name}
              </button>
            ))}
          </div>
        </div>
      )}
      {error && <div className="error">{error}</div>}
      <div className="modal-actions">
        <button type="button" className="btn btn-secondary" onClick={onCancel}>İptal</button>
        <button type="submit" className="btn btn-primary" style={{ width: 'auto' }} disabled={loading}>
          {loading ? 'Kaydediliyor...' : 'Kaydet'}
        </button>
      </div>
    </form>
  );
}

/* ---- Task Detail Modal ---- */
interface TaskDetailProps {
  task: Task;
  onClose: () => void;
}

function TaskDetail({ task, onClose }: TaskDetailProps) {
  const [comments, setComments] = useState<Comment[]>([]);
  const [activities, setActivities] = useState<ActivityLog[]>([]);
  const [subtasks, setSubtasks] = useState<Task[]>([]);
  const [labels, setLabels] = useState<Label[]>([]);
  const [newComment, setNewComment] = useState('');
  const [tab, setTab] = useState<'comments' | 'activity' | 'subtasks'>('comments');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    api.comments.list(task.id).then(setComments).catch(console.error);
    api.tasks.activities(task.id).then(setActivities).catch(console.error);
    api.tasks.subtasks(task.id).then(setSubtasks).catch(console.error);
    api.tasks.labels(task.id).then(setLabels).catch(console.error);
  }, [task.id]);

  const handleAddComment = async (e: FormEvent) => {
    e.preventDefault();
    if (!newComment.trim()) return;
    setLoading(true);
    try {
      await api.comments.create(task.id, newComment);
      setNewComment('');
      const updated = await api.comments.list(task.id);
      setComments(updated);
    } catch { /* ignore */ }
    setLoading(false);
  };

  const handleDeleteComment = async (commentId: number) => {
    await api.comments.delete(task.id, commentId);
    setComments(prev => prev.filter(c => c.id !== commentId));
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal modal-detail" onClick={e => e.stopPropagation()}>
        <div className="detail-header">
          <h3>{task.title}</h3>
          <button className="modal-close-btn" onClick={onClose} aria-label="Kapat">
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
        </div>

        <div className="detail-badges">
          <StatusBadge status={task.status} />
          <PriorityBadge priority={task.priority} />
          {task.due_date && (
            <span className={`badge badge-due ${isOverdue(task.due_date, task.status) ? 'badge-overdue' : ''}`}>
              {isOverdue(task.due_date, task.status) ? 'Gecikti: ' : 'Tarih: '}{formatDate(task.due_date)}
            </span>
          )}
        </div>

        {labels.length > 0 && (
          <div className="detail-labels">
            {labels.map(l => (
              <span key={l.id} className="label-tag" style={{ background: l.color + '22', color: l.color, borderColor: l.color + '55' }}>
                {l.name}
              </span>
            ))}
          </div>
        )}

        {task.description && <p className="detail-desc">{task.description}</p>}

        <div className="detail-meta">
          <span>{timeAgo(task.created_at)}</span>
        </div>

        <div className="detail-tabs">
          <button className={`tab-btn ${tab === 'comments' ? 'tab-active' : ''}`} onClick={() => setTab('comments')}>
            Yorumlar ({comments.length})
          </button>
          <button className={`tab-btn ${tab === 'subtasks' ? 'tab-active' : ''}`} onClick={() => setTab('subtasks')}>
            Alt Görevler ({subtasks.length})
          </button>
          <button className={`tab-btn ${tab === 'activity' ? 'tab-active' : ''}`} onClick={() => setTab('activity')}>
            Geçmiş ({activities.length})
          </button>
        </div>

        <div className="detail-tab-content">
          {tab === 'comments' && (
            <div className="comments-section">
              {comments.length === 0 && <div className="empty-tab">Henüz yorum yok</div>}
              {comments.map(c => (
                <div key={c.id} className="comment-item">
                  <div className="comment-header">
                    <strong>{c.username}</strong>
                    <span className="comment-time">{timeAgo(c.created_at)}</span>
                    <button className="comment-delete" onClick={() => handleDeleteComment(c.id)}>Sil</button>
                  </div>
                  <p>{c.content}</p>
                </div>
              ))}
              <form className="comment-form" onSubmit={handleAddComment}>
                <input
                  value={newComment}
                  onChange={e => setNewComment(e.target.value)}
                  placeholder="Yorum yaz..."
                  required
                />
                <button type="submit" className="btn btn-sm btn-primary" style={{ width: 'auto', marginTop: 0, padding: '0.5rem 1rem' }} disabled={loading}>
                  Gonder
                </button>
              </form>
            </div>
          )}

          {tab === 'subtasks' && (
            <div className="subtasks-section">
              {subtasks.length === 0 && <div className="empty-tab">Alt görev yok</div>}
              {subtasks.map(st => (
                <div key={st.id} className="subtask-item">
                  <span className={`subtask-check ${st.status === 'done' ? 'subtask-done' : ''}`} style={{ display: 'flex', alignItems: 'center' }}>
                    {st.status === 'done' 
                      ? <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="9 11 12 14 22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>
                      : <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/></svg>
                    }
                  </span>
                  <span className={st.status === 'done' ? 'subtask-title-done' : ''}>{st.title}</span>
                  <StatusBadge status={st.status} />
                </div>
              ))}
              {subtasks.length > 0 && (
                <div className="subtask-progress">
                  {subtasks.filter(s => s.status === 'done').length}/{subtasks.length} tamamlandı
                </div>
              )}
            </div>
          )}

          {tab === 'activity' && (
            <div className="activity-section">
              {activities.length === 0 && <div className="empty-tab">Geçmiş kaydı yok</div>}
              {activities.map(a => (
                <div key={a.id} className="activity-item">
                  <div className="activity-dot"></div>
                  <div className="activity-content">
                    <strong>{a.username}</strong> <span className="activity-action">{a.action}</span>
                    {a.detail && <span className="activity-detail"> - {a.detail}</span>}
                    <div className="activity-time">{timeAgo(a.created_at)}</div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { 
  Globe, Folder, Plus, Trash2, Search, X, Download, 
  LayoutGrid, List, Calendar, AlertTriangle, 
  MoreVertical, CheckCircle2, Circle, Clock, Activity,
  Check, BarChart3
} from 'lucide-react';
import { Project } from '../types';

/* ---- Main TasksPage ---- */
export default function TasksPage() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [selectedProjectId, setSelectedProjectId] = useState<number | null>(null);
  const [showProjectModal, setShowProjectModal] = useState(false);
  const [showManageMembersModal, setShowManageMembersModal] = useState(false);
  const [newProjectName, setNewProjectName] = useState('');
  const [newProjectMembers, setNewProjectMembers] = useState<number[]>([]);
  const [activeProjectMembers, setActiveProjectMembers] = useState<{ id: number; username: string }[]>([]);
  const [allLabels, setAllLabels] = useState<Label[]>([]);
  const [users, setUsers] = useState<{ id: number; username: string }[]>([]);
  const [currentUser, setCurrentUser] = useState<{ userId: number; role: string; username: string } | null>(null);
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [editTask, setEditTask] = useState<Task | null>(null);
  const [detailTask, setDetailTask] = useState<Task | null>(null);
  const [editLabels, setEditLabels] = useState<Label[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [filterPriority, setFilterPriority] = useState('');
  const [filterLabel, setFilterLabel] = useState('');
  const [draggedId, setDraggedId] = useState<number | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [quickAddTitle, setQuickAddTitle] = useState('');
  const [quickAddLoading, setQuickAddLoading] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  /* Keyboard Shortcuts */
  const handleKeyDown = useCallback((e: KeyboardEvent) => {
    const target = e.target as HTMLElement;
    const isInput = target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.tagName === 'SELECT' || target.isContentEditable;

    if (e.key === 'Escape') {
      setShowCreate(false);
      setEditTask(null);
      setDetailTask(null);
      setShowProjectModal(false);
      setShowManageMembersModal(false);
      return;
    }

    if (isInput) return;

    if (e.key === 'n' || e.key === 'N') {
      e.preventDefault();
      setShowCreate(true);
      return;
    }
    if (e.key === '/') {
      e.preventDefault();
      searchInputRef.current?.focus();
      return;
    }
  }, []);

  useEffect(() => {
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleKeyDown]);

  /* Quick Add */
  const handleQuickAdd = async (e: FormEvent) => {
    e.preventDefault();
    if (!quickAddTitle.trim()) return;
    setQuickAddLoading(true);
    try {
      const taskData: any = { title: quickAddTitle.trim() };
      if (selectedProjectId !== null) taskData.project_id = selectedProjectId;
      await api.tasks.create(taskData);
      setQuickAddTitle('');
      loadTasks();
    } catch { /* ignore */ }
    setQuickAddLoading(false);
  };

  /* CSV Export */
  const exportTasksCSV = () => {
    const header = 'ID,Başlık,Durum,Öncelik,Bitiş Tarihi,Oluşturma Tarihi\n';
    const rows = filteredTasks.map(t => {
      const due = t.due_date ? formatDate(t.due_date) : '-';
      const created = formatDate(t.created_at);
      return `${t.id},"${t.title}","${statusLabel(t.status)}","${priorityLabel(t.priority)}","${due}","${created}"`;
    }).join('\n');
    const blob = new Blob(['\uFEFF' + header + rows], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `görevler_${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const loadTasks = () => {
    setLoading(true);
    const filters: Record<string, string> = { label: filterLabel };
    if (selectedProjectId !== null) {
      filters.project_id = selectedProjectId.toString();
    }
    api.tasks.list(filters)
      .then(setTasks)
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const loadProjects = () => {
    api.projects.list().then(setProjects).catch(console.error);
  };

  useEffect(() => {
    Promise.all([
      api.projects.list().then(setProjects),
      api.labels.list().then(setAllLabels),
      api.auth.users().then(setUsers).catch(() => {
        return [] as { id: number; username: string }[];
      }),
      api.auth.me().then(setCurrentUser).catch(() => setCurrentUser(null)),
    ]).finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    loadTasks();
    if (selectedProjectId) {
      api.projects.members(selectedProjectId)
        .then(setActiveProjectMembers)
        .catch(console.error);
    } else {
      setActiveProjectMembers([]);
    }
  }, [selectedProjectId, filterLabel]);

  const handleCreateProject = async (e: FormEvent) => {
    e.preventDefault();
    if (!newProjectName.trim()) return;
    try {
      const p = await api.projects.create(newProjectName);
      let additionFailed = false;
      for (const uid of newProjectMembers) {
        try {
          await api.projects.addMember(p.id, uid);
        } catch (err: any) {
          console.error("Failed to add member", uid, err);
          additionFailed = true;
        }
      }
      if (additionFailed) {
        alert("Bazı üyeler eklenemedi. Lütfen projenizi kontrol edin.");
      }
      loadProjects();
      setNewProjectName('');
      setNewProjectMembers([]);
      setShowProjectModal(false);
      setSelectedProjectId(p.id);

      const mems = await api.projects.members(p.id).catch(() => []);
      setActiveProjectMembers(mems);
    } catch { /* ignore */ }
  };

  const handleDeleteProject = async (id: number) => {
    if (!confirm('Bu projeyi ve içindeki tüm görevleri silmek istediğinize emin misiniz?')) return;
    await api.projects.delete(id);
    if (selectedProjectId === id) setSelectedProjectId(null);
    loadProjects();
  };

  const handleCreate = async (data: any) => {
    const { labelIds, ...taskData } = data;
    if (selectedProjectId !== null) {
      taskData.project_id = selectedProjectId;
    }
    const created = await api.tasks.create(taskData);
    if (labelIds?.length) {
      for (const lid of labelIds) {
        await api.labels.addToTask(created.id, lid);
      }
    }
    setShowCreate(false);
    loadTasks();
  };

  const handleUpdate = async (data: any) => {
    if (!editTask) return;
    const { labelIds, ...taskData } = data;
    await api.tasks.update(editTask.id, taskData);

    // Sync labels
    const currentLabels = editLabels.map(l => l.id);
    const toAdd = (labelIds || []).filter((id: number) => !currentLabels.includes(id));
    const toRemove = currentLabels.filter(id => !(labelIds || []).includes(id));
    for (const lid of toAdd) await api.labels.addToTask(editTask.id, lid);
    for (const lid of toRemove) await api.labels.removeFromTask(editTask.id, lid);

    setEditTask(null);
    loadTasks();
  };

  const handleDelete = async (id: number) => {
    if (!confirm('Bu görevi silmek istediğinizden emin misiniz?')) return;
    const el = document.getElementById(`task-${id}`);
    if (el) el.classList.add('task-deleting');
    await new Promise(r => setTimeout(r, 200));
    await api.tasks.delete(id);
    loadTasks();
  };

  const handleEdit = async (task: Task) => {
    const labels = await api.tasks.labels(task.id);
    setEditLabels(labels);
    setEditTask(task);
  };

  /* Drag & Drop */
  const handleDragStart = (e: DragEvent, taskId: number) => {
    setDraggedId(taskId);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e: DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = async (e: DragEvent, newStatus: string) => {
    e.preventDefault();
    if (draggedId === null) return;
    const task = tasks.find(t => t.id === draggedId);
    if (task && task.status !== newStatus) {
      await api.tasks.update(draggedId, { status: newStatus });
      loadTasks();
    }
    setDraggedId(null);
  };

  /* Filtering */
  const filteredTasks = tasks.filter(task => {
    if (task.parent_id) return false; // Hide subtasks from main board
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      if (!task.title.toLowerCase().includes(q) && !(task.description || '').toLowerCase().includes(q)) return false;
    }
    if (filterPriority && task.priority !== filterPriority) return false;
    return true;
  });

  const todoCount = filteredTasks.filter(t => t.status === 'todo').length;
  const inProgressCount = filteredTasks.filter(t => t.status === 'in-progress').length;
  const doneCount = filteredTasks.filter(t => t.status === 'done').length;
  const completionRate = filteredTasks.length > 0 ? Math.round((doneCount / filteredTasks.length) * 100) : 0;
  const overdueCount = tasks.filter(t => isOverdue(t.due_date, t.status)).length;
  const currentProject = selectedProjectId ? projects.find(p => p.id === selectedProjectId) : null;
  const currentProjectName = currentProject?.name || 'Tüm Görevler';

  return (
    <div className="tasks-page-layout">
      {/* Mobile Hamburger */}
      <button className="hamburger-btn" onClick={() => setSidebarOpen(!sidebarOpen)} aria-label="Menu">
        <span className="hamburger-line" />
        <span className="hamburger-line" />
        <span className="hamburger-line" />
      </button>

      {/* Sidebar Overlay (mobile) */}
      {sidebarOpen && <div className="sidebar-overlay" onClick={() => setSidebarOpen(false)} />}

      {/* Sidebar */}
      <div className={`projects-sidebar ${sidebarOpen ? 'sidebar-open' : ''}`}>
        <div className="sidebar-header">
          <h3>Projeler</h3>
          <button className="btn-icon" onClick={() => setShowProjectModal(true)} title="Yeni Proje Oluştur">
            <Plus size={18} />
          </button>
        </div>
        <div className="project-list">
          <div 
            className={`project-item ${selectedProjectId === null ? 'active' : ''}`}
            onClick={() => { setSelectedProjectId(null); setSidebarOpen(false); }}
          >
            <Globe size={18} className="project-icon" />
            <span className="project-name">Tüm Görevler</span>
          </div>
          {projects.map(p => (
            <div 
              key={p.id} 
              className={`project-item ${selectedProjectId === p.id ? 'active' : ''}`}
              onClick={() => { setSelectedProjectId(p.id); setSidebarOpen(false); }}
            >
              <Folder size={18} className="project-icon" />
              <span className="project-name">{p.name}</span>
              <button 
                className="project-delete-btn" 
                onClick={(e) => { e.stopPropagation(); handleDeleteProject(p.id); }}
                title="Projeyi Sil"
              >
                <X size={14} />
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Main Content */}
      <div className="tasks-main-content">
        <div className="page-header">
          <div>
            <h2 style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
              <LayoutGrid size={24} className="text-secondary" />
              {currentProjectName} 
              <span className="task-count-badge">{tasks.filter(t => !t.parent_id).length}</span>
            </h2>
            {selectedProjectId && (
              <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.5rem', alignItems: 'center' }}>
                <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Proje Üyeleri:</span>
                {activeProjectMembers.length === 0 ? (
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)', fontStyle: 'italic' }}>Sadece siz</span>
                ) : (
                  <div className="avatar-group">
                    {activeProjectMembers.map(m => (
                      <div 
                        key={m.id} 
                        title={m.username} 
                        className="avatar-small"
                      >
                        {m.username.substring(0,2).toUpperCase()}
                      </div>
                    ))}
                  </div>
                )}
                {(currentUser?.role === 'admin' || currentProject?.user_id === currentUser?.userId) && (
                  <button className="btn-text-sm" onClick={() => setShowManageMembersModal(true)}>Üyeleri Yönet</button>
                )}
              </div>
            )}
          </div>
          <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
            <button className="btn-outline-pill" onClick={exportTasksCSV} title="CSV İndir">
              <Download size={16} />
              <span>CSV Dışa Aktar</span>
            </button>
            <button className="btn-primary-gradient" onClick={() => setShowCreate(true)}>
              <Plus size={18} />
              <span>Yeni Görev</span>
            </button>
          </div>
        </div>

        {loading ? (
          <div className="kanban-board">
            {[1,2,3].map(col => (
              <div key={col} className="kanban-column">
                <div className="skeleton-box" style={{height:'32px', width:'140px', marginBottom:'1.5rem', borderRadius: '8px'}} />
                <div className="skeleton-box skeleton-card" />
                <div className="skeleton-box skeleton-card" style={{animationDelay: '0.1s'}} />
              </div>
            ))}
          </div>
        ) : (
          <>
            {/* Stat Cards */}
            <div className="task-stats-grid">
              <div className="task-stat-card">
                <div className="task-stat-icon bg-orange">
                  <Clock size={24} />
                </div>
                <div className="task-stat-info">
                  <span className="task-stat-number">{todoCount}</span>
                  <span className="task-stat-label">Yapılacak</span>
                </div>
              </div>
              <div className="task-stat-card">
                <div className="task-stat-icon bg-blue">
                  <Activity size={24} />
                </div>
                <div className="task-stat-info">
                  <span className="task-stat-number">{inProgressCount}</span>
                  <span className="task-stat-label">Devam Ediyor</span>
                </div>
              </div>
              <div className="task-stat-card">
                <div className="task-stat-icon bg-green">
                  <CheckCircle2 size={24} />
                </div>
                <div className="task-stat-info">
                  <span className="task-stat-number">{doneCount}</span>
                  <span className="task-stat-label">Tamamlandı</span>
                </div>
              </div>
              <div className="task-stat-card">
                <div className="task-stat-icon bg-purple">
                  <BarChart3 size={24} />
                </div>
                <div className="task-stat-info">
                  <span className="task-stat-number">%{completionRate}</span>
                  <span className="task-stat-label">Tamamlanma</span>
                </div>
                <div className="progress-bar-container">
                  <div className="progress-bar-fill" style={{ width: `${completionRate}%` }} />
                </div>
              </div>
            </div>

            {overdueCount > 0 && (
              <div className="overdue-alert">
                <AlertTriangle size={18} />
                <span>{overdueCount} görev gecikti!</span>
              </div>
            )}

            {/* Quick Add */}
            <form className="quick-add-form" onSubmit={handleQuickAdd}>
              <div className="quick-add-container">
                <Plus size={18} className="quick-add-icon" />
                <input
                  className="quick-add-input"
                  type="text"
                  placeholder="Hızlı görev ekle... (Enter ile oluştur)"
                  value={quickAddTitle}
                  onChange={e => setQuickAddTitle(e.target.value)}
                  disabled={quickAddLoading}
                />
                {quickAddTitle.trim() && (
                  <button type="submit" className="quick-add-btn" disabled={quickAddLoading}>
                    {quickAddLoading ? <div className="spinner-xs" /> : <Check size={18} />}
                  </button>
                )}
              </div>
            </form>

            {/* Filter Bar */}
            <div className="filter-bar">
              <div className="search-container-modern">
                <Search size={18} className="search-icon-lucide" />
                <input
                  ref={searchInputRef}
                  type="text"
                  className="search-input-modern"
                  placeholder="Görevlerde ara..."
                  value={searchQuery}
                  onChange={e => setSearchQuery(e.target.value)}
                />
                {searchQuery && (
                  <button className="search-clear-btn" onClick={() => setSearchQuery('')}>
                    <X size={16} />
                  </button>
                )}
              </div>
              <div className="filter-actions">
                <select className="filter-select-modern" value={filterPriority} onChange={e => setFilterPriority(e.target.value)}>
                  <option value="">Tum Oncelikler</option>
                  <option value="urgent">Acil</option>
                  <option value="high">Yuksek</option>
                  <option value="medium">Orta</option>
                  <option value="low">Dusuk</option>
                </select>
                {allLabels.length > 0 && (
                  <select className="filter-select-modern" value={filterLabel} onChange={e => setFilterLabel(e.target.value)}>
                    <option value="">Tum Etiketler</option>
                    {allLabels.map(l => <option key={l.id} value={l.name}>{l.name}</option>)}
                  </select>
                )}
              </div>
            </div>

            {searchQuery && (
              <div className="search-results-info">
                <Search size={14} />
                <span>"{searchQuery}" için <strong>{filteredTasks.length}</strong> sonuç bulundu</span>
              </div>
            )}

            {tasks.length === 0 && (
              <div className="empty-state-modern">
                <div className="empty-state-icon">
                  <List size={48} />
                </div>
                <h3>Henüz görev yok!</h3>
                <p>Harika işler başarmak için ilk görevini oluştur.</p>
                <button className="btn btn-primary" onClick={() => setShowCreate(true)} style={{ marginTop: '1rem' }}>
                  Görev Oluştur
                </button>
              </div>
            )}

            {/* Kanban Board with Drag & Drop */}
            <div className="kanban-board">
              {[
                { id: 'todo', label: 'Yapılacaklar', filter: 'todo', icon: <Circle size={18} className="text-orange" /> },
                { id: 'in-progress', label: 'Devam Ediyor', filter: 'in-progress', icon: <Activity size={18} className="text-blue" /> },
                { id: 'done', label: 'Tamamlandı', filter: 'done', icon: <CheckCircle2 size={18} className="text-green" /> }
              ].map(col => (
                <div
                  className="kanban-column"
                  key={col.id}
                  onDragOver={handleDragOver}
                  onDrop={e => handleDrop(e, col.filter)}
                >
                  <h3 className="column-title">
                    <span className="flex items-center gap-2">
                      {col.icon}
                      {col.label}
                    </span>
                    <span className="column-count">{filteredTasks.filter(t => t.status === col.filter).length}</span>
                  </h3>
                  <div className="kanban-task-list">
                    {filteredTasks.filter(task => task.status === col.filter).map((task, index) => (
                      <div
                        id={`task-${task.id}`}
                        className={`task-card-modern prio-${task.priority} ${isOverdue(task.due_date, task.status) ? 'overdue' : ''} ${draggedId === task.id ? 'dragging' : ''}`}
                        style={{ animationDelay: `${index * 50}ms` }}
                        key={task.id}
                        draggable
                        onDragStart={e => handleDragStart(e, task.id)}
                        onClick={() => setDetailTask(task)}
                      >
                        <div className="task-card-header">
                          <PriorityBadge priority={task.priority} />
                          {task.due_date && (
                            <span className={`due-date-badge ${isOverdue(task.due_date, task.status) ? 'overdue' : ''}`}>
                              <Calendar size={12} />
                              {formatDate(task.due_date)}
                            </span>
                          )}
                        </div>
                        <h4 className="task-card-title">{task.title}</h4>
                        {task.description && <p className="task-card-desc">{task.description}</p>}
                        <div className="task-card-footer-modern" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0.75rem' }}>
                          <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                            <span className="task-time">
                              <Clock size={12} />
                              {timeAgo(task.created_at)}
                            </span>
                            {task.assigned_users && task.assigned_users.length > 0 && (
                              <div className="avatar-group" style={{ marginLeft: '0.5rem' }}>
                                {task.assigned_users.slice(0, 3).map(u => (
                                  <div key={u.id} title={u.username} className="avatar-small">
