                <button type="button" className="btn btn-secondary" onClick={() => setShowProjectModal(false)}>İptal</button>
                <button type="submit" className="btn btn-primary" style={{ width: 'auto' }}>Oluştur</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { Router, Request, Response } from 'express';
import db from '../db';
import { requireAuth } from '../middleware/auth';
import { AppError } from '../types';
import { createTask, getAllTasks, getTaskById, getSubtasks, getFilteredTasks, updateTask, deleteTask } from '../services/taskService';
import { getLabelsForTask, addLabelToTask, removeLabelFromTask } from '../services/labelService';
import { logActivity } from '../services/activityService';
import { getActivitiesByTask } from '../services/activityService';

const router = Router();

router.use(requireAuth);

function parseId(raw: string): number | null {
  const id = parseInt(raw, 10);
  return isNaN(id) ? null : id;
}

function sendAppError(res: Response, err: unknown): void {
  const appErr = err as AppError;
  res.status(appErr.statusCode || 500).json({ errors: appErr.errors || [{ message: appErr.message }] });
}

router.get('/', (req, res): void => {
  const { status, priority, assigned_to, project_id, search, due_before, label } = req.query;
  const isAdmin = req.session.role === 'admin';

  const hasFilters = status || priority || assigned_to || project_id !== undefined || search || due_before || label;

  if (hasFilters) {
    const parsedProjectId = project_id === 'null' ? null : (project_id ? parseInt(project_id as string, 10) : undefined);
    const tasks = getFilteredTasks(db, {
      status: status as string,
      priority: priority as string,
      assigned_to: assigned_to ? parseInt(assigned_to as string, 10) : undefined,
      project_id: parsedProjectId,
      search: search as string,
      due_before: due_before as string,
      label: label as string,
    }, req.session.userId!, isAdmin);
    res.status(200).json(tasks);
  } else {
    res.status(200).json(getAllTasks(db, req.session.userId!, isAdmin));
  }
});

router.post('/', (req: Request, res: Response): void => {
  try {
    const task = createTask(db, req.body, req.session.userId!);
    logActivity(db, task.id, req.session.userId!, 'created', `Task created: ${task.title}`);
    res.status(201).json(task);
  } catch (err) {
    sendAppError(res, err);
  }
});

router.get('/:id', (req, res): void => {
  const id = parseId(req.params.id);
  if (id === null) { res.status(400).json({ error: 'Invalid id' }); return; }

  const isAdmin = req.session.role === 'admin';
  const task = db.prepare(`
    SELECT t.* FROM tasks t
    LEFT JOIN projects p ON t.project_id = p.id
    LEFT JOIN project_members pm ON p.id = pm.project_id
    WHERE t.id = ? AND (? OR t.user_id = ? OR p.user_id = ? OR pm.user_id = ?)
    GROUP BY t.id
  `).get(id, isAdmin ? 1 : 0, req.session.userId, req.session.userId, req.session.userId);

  if (!task) { res.status(404).json({ error: 'Task not found' }); return; }
  res.status(200).json(task);
});

router.get('/:id/subtasks', (req, res): void => {
  const id = parseId(req.params.id);
  if (id === null) { res.status(400).json({ error: 'Invalid id' }); return; }
  const isAdmin = req.session.role === 'admin';
  res.status(200).json(getSubtasks(db, id, req.session.userId!, isAdmin));
});

router.get('/:id/labels', (req: Request, res: Response): void => {
  const id = parseId(req.params.id);
  if (id === null) { res.status(400).json({ error: 'Invalid id' }); return; }
  res.status(200).json(getLabelsForTask(db, id));
});

// POST /api/tasks/:id/labels — add label to task
router.post('/:id/labels', (req: Request, res: Response): void => {
  const taskId = parseId(req.params.id);
  if (taskId === null) { res.status(400).json({ error: 'Invalid task id' }); return; }
  const { label_id } = req.body;
  if (!label_id) { res.status(400).json({ error: 'label_id is required' }); return; }
  const success = addLabelToTask(db, taskId, label_id);
  if (!success) { res.status(409).json({ error: 'Label already attached or not found' }); return; }
  res.status(200).json(getLabelsForTask(db, taskId));
});

// DELETE /api/tasks/:id/labels/:labelId — remove label from task
router.delete('/:id/labels/:labelId', (req: Request, res: Response): void => {
  const taskId = parseId(req.params.id);
  const labelId = parseId(req.params.labelId);
  if (taskId === null || labelId === null) { res.status(400).json({ error: 'Invalid id' }); return; }
  removeLabelFromTask(db, taskId, labelId);
  res.status(200).json(getLabelsForTask(db, taskId));
});

router.get('/:id/activities', (req: Request, res: Response): void => {
  const id = parseId(req.params.id);
  if (id === null) { res.status(400).json({ error: 'Invalid id' }); return; }
  res.status(200).json(getActivitiesByTask(db, id));
});

router.patch('/:id', (req: Request, res: Response): void => {
  const id = parseId(req.params.id);
  if (id === null) { res.status(400).json({ error: 'Invalid id' }); return; }
  try {
    const oldTask = getTaskById(db, id);
    const task = updateTask(db, id, req.body);
    if (!task) { res.status(404).json({ error: 'Task not found' }); return; }

    // Log changes
    if (oldTask) {
      const changes: string[] = [];
      if (req.body.title && req.body.title !== oldTask.title) changes.push(`Title changed`);
      if (req.body.status && req.body.status !== oldTask.status) changes.push(`Status: ${oldTask.status} -> ${req.body.status}`);
      if (req.body.priority && req.body.priority !== oldTask.priority) changes.push(`Priority: ${oldTask.priority} -> ${req.body.priority}`);
      if (req.body.due_date !== undefined && req.body.due_date !== oldTask.due_date) changes.push(`Due date updated`);
      if (req.body.assignee_ids !== undefined) {
        const oldIds = oldTask.assigned_users?.map((u: any) => u.id).sort().join(',') || '';
        const newIds = [...req.body.assignee_ids].sort().join(',');
        if (oldIds !== newIds) changes.push(`Assignees changed`);
      }
      if (changes.length > 0) {
        logActivity(db, id, req.session.userId!, 'updated', changes.join('; '));
      }
    }

    res.status(200).json(task);
  } catch (err) {
    sendAppError(res, err);
  }
});

router.delete('/:id', (req: Request, res: Response): void => {
  const id = parseId(req.params.id);
  if (id === null) { res.status(400).json({ error: 'Invalid id' }); return; }
  if (!deleteTask(db, id)) { res.status(404).json({ error: 'Task not found' }); return; }
  res.status(204).send();
});

export default router;

import Database from 'better-sqlite3';
import { Project, CreateProjectInput, UpdateProjectInput, ValidationError } from '../types';

export function validateCreateProjectInput(input: any): ValidationError[] {
  const errors: ValidationError[] = [];
  if (!input.name || typeof input.name !== 'string' || input.name.trim() === '') {
    errors.push({ field: 'name', message: 'Project name is required' });
  } else if (input.name.length > 100) {
    errors.push({ field: 'name', message: 'Project name cannot exceed 100 characters' });
  }
  return errors;
}

export function validateUpdateProjectInput(input: any): ValidationError[] {
  const errors: ValidationError[] = [];
  if (input.name !== undefined) {
    if (typeof input.name !== 'string' || input.name.trim() === '') {
      errors.push({ field: 'name', message: 'Project name cannot be empty' });
    } else if (input.name.length > 100) {
      errors.push({ field: 'name', message: 'Project name cannot exceed 100 characters' });
    }
  }
  return errors;
}

export function createProject(db: Database.Database, input: CreateProjectInput, userId: any): Project {
  const userIdNum = Number(userId);
  const stmt = db.prepare(`
    INSERT INTO projects (name, description, user_id)
    VALUES (@name, @description, @userId)
  `);

  const result = stmt.run({
    name: input.name.trim(),
    description: input.description?.trim() || null,
    userId: userIdNum
  });

  return getProjectById(db, Number(result.lastInsertRowid)) as Project;
}

export function getProjects(db: Database.Database, userId: any, isAdmin: boolean = false): Project[] {
  const userIdNum = Number(userId);
  if (isAdmin) {
    return db.prepare('SELECT * FROM projects ORDER BY created_at DESC').all() as Project[];
  }
  return db.prepare(`
    SELECT * FROM projects 
    WHERE user_id = ? OR id IN (
      SELECT project_id FROM project_members WHERE user_id = ?
    )
    ORDER BY created_at DESC
  `).all(userIdNum, userIdNum) as Project[];
}

export function getProjectById(db: Database.Database, id: any): Project | null {
  const idNum = Number(id);
  const project = db.prepare('SELECT * FROM projects WHERE id = ?').get(idNum) as Project | undefined;
  return project || null;
}

export function updateProject(db: Database.Database, id: any, input: UpdateProjectInput, userId: any): Project | null {
  const idNum = Number(id);
  const userIdNum = Number(userId);
  const project = getProjectById(db, idNum);
  if (!project || Number(project.user_id) !== userIdNum) return null;

  const updates: string[] = [];
  const values: any = { id: idNum };

  if (input.name !== undefined) {
    updates.push('name = @name');
    values.name = input.name.trim();
  }
  if (input.description !== undefined) {
    updates.push('description = @description');
    values.description = input.description?.trim() || null;
  }

  if (updates.length > 0) {
    db.prepare(`UPDATE projects SET ${updates.join(', ')} WHERE id = @id`).run(values);
  }

  return getProjectById(db, idNum);
}

export function deleteProject(db: Database.Database, id: any, userId: any): boolean {
  const idNum = Number(id);
  const userIdNum = Number(userId);
  const project = getProjectById(db, idNum);
  if (!project || Number(project.user_id) !== userIdNum) return false;

  const result = db.prepare('DELETE FROM projects WHERE id = ?').run(idNum);
  return result.changes > 0;
}

export function getProjectMembers(db: Database.Database, projectId: any): { id: number, username: string, email: string }[] {
  const projectIdNum = Number(projectId);
  return db.prepare(`
    SELECT u.id, u.username, u.email 
    FROM users u
    JOIN project_members pm ON u.id = pm.user_id
    WHERE pm.project_id = ?
  `).all(projectIdNum) as any[];
}

export function addMemberToProject(db: Database.Database, projectId: any, newUserId: any, requestingUserId: any, isAdmin: boolean = false): boolean {
  const projectIdNum = Number(projectId);
  const newUserIdNum = Number(newUserId);
  const requestingUserIdNum = Number(requestingUserId);

  const project = getProjectById(db, projectIdNum);
  if (!project) return false;
  if (Number(project.user_id) !== requestingUserIdNum && !isAdmin) return false;

  // verify user exists
  const userExists = db.prepare('SELECT 1 FROM users WHERE id = ?').get(newUserIdNum);
  if (!userExists) return false;

  try {
    db.prepare('INSERT INTO project_members (project_id, user_id) VALUES (?, ?)').run(projectIdNum, newUserIdNum);
    return true;
  } catch (e: any) {
    if (e.code === 'SQLITE_CONSTRAINT_PRIMARYKEY') return true;
    throw e;
  }
}

export function removeMemberFromProject(db: Database.Database, projectId: any, targetUserId: any, requestingUserId: any, isAdmin: boolean = false): boolean {
  const projectIdNum = Number(projectId);
  const targetUserIdNum = Number(targetUserId);
  const requestingUserIdNum = Number(requestingUserId);

  const project = getProjectById(db, projectIdNum);
  if (!project) return false;
  if (Number(project.user_id) !== requestingUserIdNum && !isAdmin) return false;

  const result = db.prepare('DELETE FROM project_members WHERE project_id = ? AND user_id = ?').run(projectIdNum, targetUserIdNum);
  return result.changes > 0;
}

import { Task, TaskStatus, TaskPriority, CreateTaskInput, UpdateTaskInput, ValidationError, AppError } from '../types';
import Database from 'better-sqlite3';

const VALID_STATUSES: TaskStatus[] = ['todo', 'in-progress', 'done'];
const VALID_PRIORITIES: TaskPriority[] = ['low', 'medium', 'high', 'urgent'];

function throwIfInvalid(errors: ValidationError[]): void {
  if (errors.length === 0) return;
  const err = new Error(errors[0].message) as AppError;
  err.statusCode = 400;
  err.errors = errors;
  throw err;
}

export function validateCreateTaskInput(input: Partial<CreateTaskInput>): ValidationError[] {
  const errors: ValidationError[] = [];

  if (!input.title || input.title.trim().length === 0) {
    errors.push({ field: 'title', message: 'Title is required' });
  } else if (input.title.trim().length > 200) {
    errors.push({ field: 'title', message: 'Title must be at most 200 characters' });
  }

  if (input.status && !VALID_STATUSES.includes(input.status)) {
    errors.push({ field: 'status', message: `Status must be one of: ${VALID_STATUSES.join(', ')}` });
  }

  if (input.priority && !VALID_PRIORITIES.includes(input.priority)) {
    errors.push({ field: 'priority', message: `Priority must be one of: ${VALID_PRIORITIES.join(', ')}` });
  }

  if (input.due_date && isNaN(Date.parse(input.due_date))) {
    errors.push({ field: 'due_date', message: 'Invalid date format for due_date' });
  }

  if (input.assignee_ids && !Array.isArray(input.assignee_ids)) {
    errors.push({ field: 'assignee_ids', message: 'Assignees must be an array of IDs' });
  }

  return errors;
}

export function validateUpdateTaskInput(input: Partial<UpdateTaskInput>): ValidationError[] {
  const errors: ValidationError[] = [];

  if (input.title !== undefined) {
    if (input.title.trim().length === 0) {
      errors.push({ field: 'title', message: 'Title cannot be empty' });
    } else if (input.title.trim().length > 200) {
      errors.push({ field: 'title', message: 'Title must be at most 200 characters' });
    }
  }

  if (input.status !== undefined && !VALID_STATUSES.includes(input.status)) {
    errors.push({ field: 'status', message: `Status must be one of: ${VALID_STATUSES.join(', ')}` });
  }

  if (input.priority !== undefined && !VALID_PRIORITIES.includes(input.priority)) {
    errors.push({ field: 'priority', message: `Priority must be one of: ${VALID_PRIORITIES.join(', ')}` });
  }

  if (input.due_date !== undefined && input.due_date !== null && isNaN(Date.parse(input.due_date))) {
    errors.push({ field: 'due_date', message: 'Invalid date format for due_date' });
  }

  if (input.assignee_ids !== undefined && input.assignee_ids !== null && !Array.isArray(input.assignee_ids)) {
    errors.push({ field: 'assignee_ids', message: 'Assignees must be an array of IDs' });
  }

  return errors;
}

function parseTaskRow(row: any): Task {
  if (!row) return row;
  const task = { ...row };
  if (task.assigned_users_json) {
    task.assigned_users = JSON.parse(task.assigned_users_json);
    delete task.assigned_users_json;
  } else {
    task.assigned_users = [];
  }
  return task;
}

const selectTasksClause = `
  SELECT t.*, 
    COALESCE(
      (SELECT json_group_array(json_object('id', u.id, 'username', u.username))
       FROM task_assignees ta
       JOIN users u ON ta.user_id = u.id
       WHERE ta.task_id = t.id), '[]'
    ) as assigned_users_json
`;

export function createTask(db: Database.Database, input: CreateTaskInput, userId: number): Task {
  throwIfInvalid(validateCreateTaskInput(input));

  let newId: number | bigint = 0;

  db.transaction(() => {
    const result = db.prepare(
      'INSERT INTO tasks (title, description, status, priority, due_date, parent_id, project_id, user_id) VALUES (?, ?, ?, ?, ?, ?, ?, ?)'
    ).run(
      input.title.trim(),
      input.description?.trim() ?? null,
      input.status ?? 'todo',
      input.priority ?? 'medium',
      input.due_date ?? null,
      input.parent_id ?? null,
      input.project_id ?? null,
      userId
    );

    newId = result.lastInsertRowid;

    if (input.assignee_ids && input.assignee_ids.length > 0) {
      const stmt = db.prepare('INSERT OR IGNORE INTO task_assignees (task_id, user_id) VALUES (?, ?)');
      for (const assigneeId of input.assignee_ids) {
        stmt.run(newId, assigneeId);
      }
    }
  })();

  return getTaskById(db, Number(newId))!;
}

export function getTaskById(db: Database.Database, id: number): Task | null {
  const row = db.prepare(`${selectTasksClause} FROM tasks t WHERE t.id = ?`).get(id);
  return row ? parseTaskRow(row) : null;
}

export function getAllTasks(db: Database.Database, userId: number, isAdmin: boolean = false): Task[] {
  let rows: any[];
  if (isAdmin) {
    rows = db.prepare(`${selectTasksClause} FROM tasks t ORDER BY t.created_at DESC`).all();
  } else {
    rows = db.prepare(`
      ${selectTasksClause} FROM tasks t
      LEFT JOIN projects p ON t.project_id = p.id
      LEFT JOIN project_members pm ON p.id = pm.project_id
      LEFT JOIN task_assignees ta ON ta.task_id = t.id
      WHERE t.user_id = ? 
         OR p.user_id = ? 
         OR pm.user_id = ?
         OR ta.user_id = ?
      GROUP BY t.id
      ORDER BY t.created_at DESC
    `).all(userId, userId, userId, userId);
  }
  return rows.map(parseTaskRow);
}

export function getSubtasks(db: Database.Database, parentId: number, userId: number, isAdmin: boolean = false): Task[] {
  let rows: any[];
  if (isAdmin) {
    rows = db.prepare(`${selectTasksClause} FROM tasks t WHERE t.parent_id = ? ORDER BY t.created_at ASC`).all(parentId);
  } else {
    rows = db.prepare(`
      ${selectTasksClause} FROM tasks t
      LEFT JOIN projects p ON t.project_id = p.id
      LEFT JOIN project_members pm ON p.id = pm.project_id
      LEFT JOIN task_assignees ta ON ta.task_id = t.id
      WHERE t.parent_id = ? AND (
        t.user_id = ? OR p.user_id = ? OR pm.user_id = ? OR ta.user_id = ?
      )
      GROUP BY t.id
      ORDER BY t.created_at ASC
    `).all(parentId, userId, userId, userId, userId);
  }
  return rows.map(parseTaskRow);
}

export interface TaskFilters {
  status?: string;
  priority?: string;
  search?: string;
  due_before?: string;
  label?: string;
  project_id?: number | null;
  assigned_to?: number; // Filtering by a specific assignee ID
}

export function getFilteredTasks(db: Database.Database, filters: TaskFilters, userId: number, isAdmin: boolean = false): Task[] {
  const conditions: string[] = [];
  const values: (string | number)[] = [];

  if (filters.status) { conditions.push('t.status = ?'); values.push(filters.status); }
  if (filters.priority) { conditions.push('t.priority = ?'); values.push(filters.priority); }

  if (filters.assigned_to) { 
    conditions.push('EXISTS (SELECT 1 FROM task_assignees ta_flt WHERE ta_flt.task_id = t.id AND ta_flt.user_id = ?)'); 
    values.push(filters.assigned_to); 
  }

  if (filters.project_id !== undefined) {
    if (filters.project_id === null) {
      conditions.push('t.project_id IS NULL');
    } else {
      conditions.push('t.project_id = ?');
      values.push(filters.project_id);
    }
  }
  if (filters.due_before) { conditions.push('t.due_date <= ?'); values.push(filters.due_before); }
  if (filters.search) {
    conditions.push('(t.title LIKE ? OR t.description LIKE ?)');
    values.push(`%${filters.search}%`, `%${filters.search}%`);
  }
  if (filters.label) {
    conditions.push('EXISTS (SELECT 1 FROM task_labels tl JOIN labels l ON tl.label_id = l.id WHERE tl.task_id = t.id AND l.name = ?)');
    values.push(filters.label);
  }

  if (!isAdmin) {
    conditions.push(`(t.user_id = ? OR p.user_id = ? OR pm.user_id = ? OR ta_auth.user_id = ?)`);
    values.push(userId, userId, userId, userId);
  }

  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
  const fromClause = !isAdmin 
    ? `tasks t 
       LEFT JOIN projects p ON t.project_id = p.id
       LEFT JOIN project_members pm ON p.id = pm.project_id
       LEFT JOIN task_assignees ta_auth ON ta_auth.task_id = t.id`
    : `tasks t`;

  const rows = db.prepare(`
    ${selectTasksClause} FROM ${fromClause}
    ${where} 
    GROUP BY t.id
    ORDER BY t.created_at DESC
  `).all(...values);

  return rows.map(parseTaskRow);
}

export function updateTask(db: Database.Database, id: number, input: UpdateTaskInput): Task | null {
  throwIfInvalid(validateUpdateTaskInput(input));

  db.transaction(() => {
    const updates: string[] = [];
    const values: (string | number | null)[] = [];

    if (input.title !== undefined) { updates.push('title = ?'); values.push(input.title.trim()); }
    if (input.description !== undefined) { updates.push('description = ?'); values.push(input.description.trim()); }
    if (input.status !== undefined) { updates.push('status = ?'); values.push(input.status); }
    if (input.priority !== undefined) { updates.push('priority = ?'); values.push(input.priority); }
    if (input.due_date !== undefined) { updates.push('due_date = ?'); values.push(input.due_date); }
    if (input.project_id !== undefined) { updates.push('project_id = ?'); values.push(input.project_id); }

    if (updates.length > 0) {
      updates.push('updated_at = CURRENT_TIMESTAMP');
      values.push(id);
      db.prepare(`UPDATE tasks SET ${updates.join(', ')} WHERE id = ?`).run(...values);
    }

    if (input.assignee_ids !== undefined) {
      db.prepare('DELETE FROM task_assignees WHERE task_id = ?').run(id);
      if (input.assignee_ids !== null && input.assignee_ids.length > 0) {
        const stmt = db.prepare('INSERT OR IGNORE INTO task_assignees (task_id, user_id) VALUES (?, ?)');
        for (const assigneeId of input.assignee_ids) {
          stmt.run(id, assigneeId);
        }
      }
    }
  })();

  return getTaskById(db, id);
}

export function deleteTask(db: Database.Database, id: number): boolean {
  const result = db.prepare('DELETE FROM tasks WHERE id = ?').run(id);
  return result.changes > 0;
}

